import numpy as np

def hamming_distance_kanerva(state: list, prototypes: list, threshold: int) -> tuple:
    distances = []
    for proto in prototypes:
        dist = sum(s != p for s, p in zip(state, proto))
        distances.append(dist)
    active_indices = sorted(i for i, d in enumerate(distances) if d <= threshold)
    return (distances, active_indices)
